export type KeyOf<T extends Record<string, any>> = Extract<keyof T, string>;

export type LinkCardinality = "one" | "many";
export type LinkSide = "source" | "target";

export type ObjectType = {
 properties: {
 [apiName: string]: {
 propertyRid: string;
 dataType: PrimitiveDataType;
 };
 };
 links: {
 [linkApiName: string]: {
 linkRid: string;
 side: LinkSide;
 cardinality: LinkCardinality;
 otherSide: {
 objectTypeRid: KeyOf<ObjectTypes>;
 side: LinkSide;
 cardinality: LinkCardinality;
 };
 };
 };
};

export interface ObjectTypes {
 [objectTypeRid: string]: ObjectType;
}

/** The output type of objectSearchAround: Object if cardinality is "one", ObjectSet if "many". */
export type ObjectSearchAroundOutput<OtherSide extends { cardinality: LinkCardinality; objectTypeRid: string }> =
 OtherSide["cardinality"] extends "one"
 ? DataType.Object<OtherSide["objectTypeRid"]>
 : DataType.ObjectSet<OtherSide["objectTypeRid"]>;

/** Maps selected property names to their data types from the given object type. */
export type SelectedStructShape<
 Objects extends ObjectTypes,
 ObjectTypeRid extends KeyOf<Objects>,
 Properties extends Array<KeyOf<Objects[ObjectTypeRid]["properties"]>>,
> = {
 [K in Properties[number]]: Objects[ObjectTypeRid]["properties"][K]["dataType"];
};

export type ActionType = {
 parameters: {
 [parameterId: string]: {
 parameterRid: string;
 dataType: PhysicalType;
 };
 };
};

export interface ActionTypes {
 [actionTypeRid: string]: ActionType;
}

export type FunctionType = {
 parameters: {
 [displayName: string]: {
 parameterApiName: string;
 dataType: PhysicalType;
 };
 };
 returnType: PhysicalType;
};

export interface FunctionTypes {
 [functionTypeRid: string]: {
 [version: string]: FunctionType;
 };
}

export namespace DataType {
 export interface Array<T extends PrimitiveDataType> {
 type: "array";
 elementType: T;
 }
 export type Binary = { type: "binary" };
 export type Boolean = { type: "boolean" };
 export type Byte = { type: "byte" };
 export type Date = { type: "date" };
 export type Decimal = { type: "decimal" };
 export type Double = { type: "double" };
 export type Float = { type: "float" };
 export type Integer = { type: "integer" };
 export interface List<T extends PhysicalType> {
 type: "list";
 elementType: T;
 }
 export type Long = { type: "long" };
 export type Object<ObjectTypeRid extends keyof ObjectTypes> = { type: "object"; objectTypeRid: ObjectTypeRid };

 export type ObjectSet<ObjectTypeRid extends keyof ObjectTypes> = {
 type: "objectSet";
 objectTypeRid: ObjectTypeRid;
 };
 export type OntologyEdits = {
 type: "ontologyEdits";
 };
 export type Short = { type: "short" };
 export type String = { type: "string" };
 export interface Struct<Shape extends { [name: string]: PrimitiveDataType }> {
 type: "struct";
 shape: Shape;
 }
 export type Timestamp = { type: "timestamp" };
}

export type PrimitiveDataType =
 | DataType.Array<PrimitiveDataType>
 | DataType.Binary
 | DataType.Boolean
 | DataType.Byte
 | DataType.Date
 | DataType.Decimal
 | DataType.Double
 | DataType.Float
 | DataType.Integer
 | DataType.Long
 | DataType.Short
 | DataType.String
 | DataType.Struct<{ [name: string]: PrimitiveDataType }>
 | DataType.Timestamp;

export type PhysicalType =
 | PrimitiveDataType
 | DataType.Object<KeyOf<ObjectTypes>>
 | DataType.ObjectSet<KeyOf<ObjectTypes>>
 | DataType.List<PhysicalType>;

export type DataType = PhysicalType | DataType.OntologyEdits;

export interface Literal<Type extends PrimitiveDataType> {
 type: "literal";
 dataType: Type;
}

export interface Literals {
 boolean: (value: boolean) => Literal<DataType.Boolean>;
 /** ISO 8601 date string in the format YYYY-MM-DD */
 date: (value: string) => Literal<DataType.Date>;
 double: (value: number) => Literal<DataType.Double>;
 float: (value: string) => Literal<DataType.Float>;
 integer: (value: number) => Literal<DataType.Integer>;
 long: (value: number) => Literal<DataType.Long>;
 short: (value: number) => Literal<DataType.Short>;
 string: (value: string) => Literal<DataType.String>;
 timestamp: (value: string) => Literal<DataType.Timestamp>;
 array: <T extends PrimitiveDataType>(elements: Array<Literal<T>>) => Literal<DataType.Array<T>>;
 struct: <Shape extends { [name: string]: PrimitiveDataType }>(fields: {
 [name in keyof Shape]: Literal<Shape[name]>;
 }) => Literal<DataType.Struct<Shape>>;
}

export interface Parameter<T extends PhysicalType> {
 dataType: T;
 type: "parameter";
}
export interface TransformOutput<T extends DataType> {
 dataType: T;
 type: "transformOutput";
}

export type Reference<T extends PhysicalType> = Parameter<T> | TransformOutput<T>;

export interface Expression<T extends PrimitiveDataType> {
 dataType: T;
 type: "expression";
}

export type ExpressionInput<T extends PrimitiveDataType> = Reference<T> | Expression<T> | Literal<T>;

export type TransformMetadata = {
 displayName?: string;
 comment?: string;
 /** When modifying an existing transform you must use its existing ID. Do not provide an ID for a new transform. */
 id?: string;
};

export type StringTemplate = string | Reference<PrimitiveDataType> | Array<string | Reference<PrimitiveDataType>>;

/** References a property on an object type for use in objectSetFormat. */
export type ObjectPropertyRef<ObjectTypeRid extends KeyOf<ObjectTypes>> = {
 type: "objectProperty";
 propertyApiName: KeyOf<ObjectTypes[ObjectTypeRid]["properties"]>;
};

/** Template array for formatting objects - strings, property refs, and external references. */
export type ObjectFormatTemplate<ObjectTypeRid extends KeyOf<ObjectTypes>> = Array<
 string | ObjectPropertyRef<ObjectTypeRid> | Reference<PrimitiveDataType>
>;

/** Extracts property apiNames that have the specified dataType. */
export type PropertiesOfType<
 Properties extends { [apiName: string]: { dataType: PrimitiveDataType } },
 T extends PrimitiveDataType,
> = string &
 KeyOf<{
 [K in KeyOf<Properties> as Properties[K]["dataType"] extends T ? K : never]: Properties[K];
 }>;

export type LlmTool = { type: "tool" };

/** Specifies an object type and optionally which properties/links the LLM can access. */
export type OntologyEntity<Objects extends ObjectTypes> = {
 [K in KeyOf<Objects>]: {
 objectTypeRid: K;
 /** If omitted, all properties are accessible. */
 allowedProperties?: Array<KeyOf<Objects[K]["properties"]>>;
 /**
 * If omitted, no links are accessible. When specified, the linked object type on the other side is
 * automatically added with all properties accessible.
 */
 allowedLinks?: Array<KeyOf<Objects[K]["links"]>>;
 };
}[KeyOf<Objects>];

export type LlmToolBuilder<Objects extends ObjectTypes> = {
 /**
 * Allows the LLM to apply ontology actions
 */
 applyAction(actionTypeRid: string): LlmTool;
 /**
 * Provides the LLM with a calculator tool to perform mathematical calculations.
 */
 calculator(): LlmTool;
 /**
 * Allows the LLM to execute the selected ontology function
 */
 callFunction(functionTypeRid: string, functionVersion: string): LlmTool;
 /**
 * Allows the LLM to access the current date in the specified timezone.
 *
 * @param timezone - IANA timezone string, e.g., "America/Los_Angeles". If not provided, the timezone defaults to UTC.
 */
 currentDate(timezone?: string): LlmTool;
 /**
 * Allows the LLM to query the selected object types using SQL. Requires OSv2 object types.
 * Tool cannot directly return an objectSet, so use `queryObjectsLegacy` for object set outputs if you need it to come from a tool call.
 *
 * @param ontologyEntities - Specifies the object types, properties, and links that can be queried.
 * When links are specified, linked object types on the other side are automatically added with all properties accessible.
 * @param rowLimit - Maximum number of rows the LLM can retrieve per query.
 */
 queryObjects(args: { ontologyEntities: Array<OntologyEntity<Objects>>; rowLimit: number }): LlmTool;
 /**
 * Allows the LLM to query the selected object types. Works with both OSv1 and OSv2 object types.
 *
 * @param ontologyEntities - Specifies the object types, properties, and links that can be queried.
 * When links are specified, linked object types on the other side are automatically added with all properties accessible.
 */
 queryObjectsLegacy(args: { ontologyEntities: Array<OntologyEntity<Objects>> }): LlmTool;
};

export type TakeNoAction = {
 type: "takeNoAction";
 dataType: DataType.OntologyEdits;
};

export type LoopOutputType = PhysicalType | DataType.OntologyEdits;
export type LoopReturnType<R extends LoopOutputType> = R extends DataType.OntologyEdits
 ? DataType.OntologyEdits
 : DataType.List<R & PhysicalType>;

export type ConditionalOutputType =
 | PrimitiveDataType
 | DataType.Object<KeyOf<ObjectTypes>>
 | DataType.ObjectSet<KeyOf<ObjectTypes>>
 | DataType.List<DataType.Object<KeyOf<ObjectTypes>>>
 | DataType.OntologyEdits;

export type ConditionalBranchValue<T extends ConditionalOutputType> = T extends DataType.OntologyEdits
 ? TakeNoAction | (() => TransformOutput<T>)
 : Reference<T & PhysicalType> | (() => TransformOutput<T>);

export type ConditionalConfig<T extends ConditionalOutputType> = {
 cases: Array<{ when: Condition; then: ConditionalBranchValue<T> }>;
 defaultValue: ConditionalBranchValue<T>;
};

export type ConditionOperand<T extends PrimitiveDataType> = Literal<T> | Reference<T>;

export interface Condition {
 type: "condition";
}

export type ConditionBuilder = {
 equals<T extends PrimitiveDataType>(left: ConditionOperand<T>, right: ConditionOperand<T>): Condition;
 greaterThan<T extends PrimitiveDataType>(left: ConditionOperand<T>, right: ConditionOperand<T>): Condition;
 isNotNull<T extends PrimitiveDataType>(operand: ConditionOperand<T>): Condition;
 lessThan<T extends PrimitiveDataType>(left: ConditionOperand<T>, right: ConditionOperand<T>): Condition;
 greaterThanOrEquals<T extends PrimitiveDataType>(left: ConditionOperand<T>, right: ConditionOperand<T>): Condition;
 lessThanOrEquals<T extends PrimitiveDataType>(left: ConditionOperand<T>, right: ConditionOperand<T>): Condition;
 allAreTrue(...conditions: Condition[]): Condition;
 anyIsTrue(...conditions: Condition[]): Condition;
 noneAreTrue(...conditions: Condition[]): Condition;
 /** Use with conditionals where other branches make ontology edits, and one or more branches should not make ontology edits. */
 takeNoAction(): TakeNoAction;
};

export type ObjectSetFilterValue<T extends PrimitiveDataType> = Literal<T> | Reference<T>;

export type RelativeDateRangeUnit = "day" | "week" | "month" | "year";

/** IANA timezone identifier (e.g., "America/New_York", "Europe/London", "UTC"). */
export type IANATimezone = string;

/**
* Filters dates within a range relative to the current date.
* Bounds are offsets from "now" where negative values represent the past and positive values represent the future.
*
* @example
* // Last 30 days (from 30 days ago to today)
* { lowerBound: -30, lowerBoundUnit: "day", upperBound: 0, upperBoundUnit: "day" }
*
* @example
* // Next 2 weeks
* { lowerBound: 0, lowerBoundUnit: "day", upperBound: 2, upperBoundUnit: "week", timezone: "America/New_York" }
*/
export type RelativeDateRangeConfig = {
 /** Offset from now for the start of the range (negative = past, positive = future). */
 lowerBound: number | Reference<DataType.Integer>;
 lowerBoundUnit: RelativeDateRangeUnit;
 /** Offset from now for the end of the range (negative = past, positive = future). */
 upperBound: number | Reference<DataType.Integer>;
 upperBoundUnit: RelativeDateRangeUnit;
 /**
 * Timezone for interpreting date boundaries. Defaults to UTC.
 * Matters when ranges cross daylight saving time boundaries.
 */
 timezone?: IANATimezone;
};

/**
* Filters timestamps within a range relative to the current time.
* Bounds are offsets from "now" in milliseconds where negative values represent the past and positive values represent the future.
*
* @example
* // Last hour (from 1 hour ago to now)
* { lowerBound: -3600000, upperBound: 0 }
*
* @example
* // Last 24 hours
* { lowerBound: -86400000, upperBound: 0 }
*/
export type RelativeTimeRangeConfig = {
 /** Offset from now in milliseconds for the start of the range (negative = past, positive = future). */
 lowerBound: number | Reference<DataType.Long>;
 /** Offset from now in milliseconds for the end of the range (negative = past, positive = future). */
 upperBound: number | Reference<DataType.Long>;
};

/**
* Maximum edit distance for fuzzy keyword matching.
* Edit operations include insertions, deletions, substitutions, and transpositions.
*
* - `"auto"` - Automatically determines based on term length: exact match for 0-2 chars, 1 edit for 3-5 chars, 2 edits for 6+ chars
* - `"levenshtein_zero"` - Exact match only
* - `"levenshtein_one"` - Up to 1 edit allowed
* - `"levenshtein_two"` - Up to 2 edits allowed
*/
export type FuzzyMatchingMaxEditDistance = "auto" | "levenshtein_zero" | "levenshtein_one" | "levenshtein_two";

export interface ObjectSetFilter {
 type: "objectSetFilter";
}

/** Extracts the data type of a property from an object type. */
type PropertyDataType<
 Objects extends ObjectTypes,
 ObjectTypeRid extends KeyOf<Objects>,
 PropName extends KeyOf<Objects[ObjectTypeRid]["properties"]>,
> = Objects[ObjectTypeRid]["properties"][PropName]["dataType"];

/** Builder for constructing filter expressions used in filterObjectSet. */
export type ObjectSetFilterBuilder<Objects extends ObjectTypes, ObjectTypeRid extends KeyOf<Objects>> = {
 equals<PropName extends KeyOf<Objects[ObjectTypeRid]["properties"]>>(
 propertyApiName: PropName,
 value: ObjectSetFilterValue<PropertyDataType<Objects, ObjectTypeRid, PropName>>,
 ): ObjectSetFilter;
 greaterThan<PropName extends KeyOf<Objects[ObjectTypeRid]["properties"]>>(
 propertyApiName: PropName,
 value: ObjectSetFilterValue<PropertyDataType<Objects, ObjectTypeRid, PropName>>,
 ): ObjectSetFilter;
 greaterThanOrEqualTo<PropName extends KeyOf<Objects[ObjectTypeRid]["properties"]>>(
 propertyApiName: PropName,
 value: ObjectSetFilterValue<PropertyDataType<Objects, ObjectTypeRid, PropName>>,
 ): ObjectSetFilter;
 lessThan<PropName extends KeyOf<Objects[ObjectTypeRid]["properties"]>>(
 propertyApiName: PropName,
 value: ObjectSetFilterValue<PropertyDataType<Objects, ObjectTypeRid, PropName>>,
 ): ObjectSetFilter;
 lessThanOrEqualTo<PropName extends KeyOf<Objects[ObjectTypeRid]["properties"]>>(
 propertyApiName: PropName,
 value: ObjectSetFilterValue<PropertyDataType<Objects, ObjectTypeRid, PropName>>,
 ): ObjectSetFilter;
 isNotNull(propertyApiName: KeyOf<Objects[ObjectTypeRid]["properties"]>): ObjectSetFilter;
 /** Filter dates within a relative range (e.g., last 30 days). */
 relativeDateRange(
 propertyApiName: PropertiesOfType<Objects[ObjectTypeRid]["properties"], DataType.Date>,
 range: RelativeDateRangeConfig,
 ): ObjectSetFilter;
 /** Filter timestamps within a relative range (e.g., last hour). */
 relativeTimeRange(
 propertyApiName: PropertiesOfType<Objects[ObjectTypeRid]["properties"], DataType.Timestamp>,
 range: RelativeTimeRangeConfig,
 ): ObjectSetFilter;
 /**
 * Search for keywords in one or more string properties (any order).
 * Supports fuzzy matching with configurable edit distance.
 */
 containsKeywords(
 propertyApiNames:
 | PropertiesOfType<Objects[ObjectTypeRid]["properties"], DataType.String>
 | Array<PropertiesOfType<Objects[ObjectTypeRid]["properties"], DataType.String>>,
 searchText: ObjectSetFilterValue<DataType.String>,
 options?: { fuzzyMatchingMaxEditDistance?: FuzzyMatchingMaxEditDistance },
 ): ObjectSetFilter;
 /** Search for keywords in a string property (must appear in order). */
 containsKeywordsInOrder(
 propertyApiName: PropertiesOfType<Objects[ObjectTypeRid]["properties"], DataType.String>,
 searchText: ObjectSetFilterValue<DataType.String>,
 ): ObjectSetFilter;
 allAreTrue(...conditions: ObjectSetFilter[]): ObjectSetFilter;
 anyIsTrue(...conditions: ObjectSetFilter[]): ObjectSetFilter;
 noneAreTrue(...conditions: ObjectSetFilter[]): ObjectSetFilter;
};

export type ListElementType = PrimitiveDataType | DataType.Object<KeyOf<ObjectTypes>>;

export interface Transforms<Objects extends ObjectTypes, Actions extends ActionTypes, Functions extends FunctionTypes> {
 array<T extends PrimitiveDataType>(
 elements: Array<Literal<T>>,
 metadata?: TransformMetadata,
 ): TransformOutput<DataType.Array<T>>;
 boolean(value: boolean, metadata?: TransformMetadata): TransformOutput<DataType.Boolean>;
 /** ISO 8601 date string in the format YYYY-MM-DD */
 date(value: string, metadata?: TransformMetadata): TransformOutput<DataType.Date>;
 double(value: number, metadata?: TransformMetadata): TransformOutput<DataType.Double>;
 float(value: string, metadata?: TransformMetadata): TransformOutput<DataType.Float>;
 integer(value: number, metadata?: TransformMetadata): TransformOutput<DataType.Integer>;
 long(value: number, metadata?: TransformMetadata): TransformOutput<DataType.Long>;
 objectList<const ObjectTypeRid extends KeyOf<Objects>>(
 objects: Array<Reference<DataType.Object<ObjectTypeRid>>>,
 metadata?: TransformMetadata,
 ): TransformOutput<DataType.List<DataType.Object<ObjectTypeRid>>>;
 objectSet<const ObjectTypeRid extends KeyOf<Objects>>(
 objectTypeRid: ObjectTypeRid,
 metadata?: TransformMetadata,
 ): TransformOutput<DataType.ObjectSet<ObjectTypeRid>>;
 short(value: number, metadata?: TransformMetadata): TransformOutput<DataType.Short>;
 /** Use this to create string variables, including both plain strings as well as complex strings that combine inputs and transform outputs */
 string(value: StringTemplate, metadata?: TransformMetadata): TransformOutput<DataType.String>;
 /** ISO timestamp string, e.g. "2024-01-15T10:30:00Z" */
 timestamp(value: string, metadata?: TransformMetadata): TransformOutput<DataType.Timestamp>;

 applyExpression<T extends PrimitiveDataType>(
 expression: Expression<T>,
 metadata?: TransformMetadata,
 ): TransformOutput<T>;

 objectProperty<
 ObjectTypeRid extends KeyOf<Objects>,
 PropertyApiName extends KeyOf<Objects[ObjectTypeRid]["properties"]>,
 >(
 object: Reference<DataType.Object<ObjectTypeRid>>,
 propertyApiName: PropertyApiName,
 metadata?: TransformMetadata,
 ): TransformOutput<Objects[ObjectTypeRid]["properties"][PropertyApiName]["dataType"]>;

 /**
 * Creates a transform that runs an LLM with the provided system and user prompts and returns the chosen output type.
 *
 * Define prompts inline rather than as separate variables for better readability, e.g., `["You are a helpful assistant.", someReference, "Help the user."]`.
 * Only define separate prompt variables if they're reused multiple times.
 *
 * @param systemPrompt - Guides the LLM's behavior and provides overarching context and instructions
 * @param taskPrompt - Specifies task-specific context and input data
 * @param [tools] - A set of tools provided to the LLM that it can use to gain more information.
 * @param outputType - Data type the LLM should return
 *
 * @example
 * ```ts
 * const useLlmTransform = L.transforms.useLlm(
 * {
 * systemPrompt: ["Your goal is to answer employees' questions at company:", someTransformOutputReference],
 * taskPrompt: ["Answer the following question: ", someInputReference, "Be thorough."],
 * tools: [L.tools.calculator(), L.tools.currentDate()],
 * outputType: L.types.string,
 * },
 * { displayName: "Answer Employee Question" }
 * );
 * ```
 */
 useLlm<T extends PhysicalType>(
 args: {
 systemPrompt: StringTemplate;
 taskPrompt: StringTemplate;
 tools?: LlmTool[];
 outputType: T;
 },
 metadata?: TransformMetadata,
 ): TransformOutput<T>;

 /**
 * Defines a group of related transforms. The output of the group is the output of the transform returned from the groupDefinitionFn.
 *
 * @example
 * ```ts
 * const combinedString = L.transforms.group(() => {
 * const innerString1 = L.transforms.string("inner string 1");
 * const innerString2 = L.transforms.string(["inner string 2", innerString1]);
 * return innerString2;
 * });
 *
 * const L.transforms.string(["outer string", combinedString]);
 * ```
 */
 group<T extends DataType>(f: () => TransformOutput<T>, metadata?: TransformMetadata): TransformOutput<T>;
 /**
 * Creates a conditional transform for if/else logic.
 * - Only use method on the ConditionBuilder (C) object (equals, greaterThan, etc.) to create conditions.
 * - Inline branch values by using arrow functions, unless the branch value needs to be re-used.
 * - Always wrap inputs/transforms in comparisons (C.equals, C.greaterThan) when using logical operators (C.anyIsTrue, C.allAreTrue, C.noneAreTrue). E.g., use C.anyIsTrue(C.equals(input1, value1), C.equals(input2, value2)) instead of C.anyIsTrue(input1, input2).
 *
 * @example
 * ```ts
 * const status = L.input({ apiName: "status", type: L.types.string });
 * const result = L.transforms.conditional(C => ({
 * cases: [
 * {
 * when: C.allAreTrue(
 * C.equals(status, L.literals.string("active")),
 * C.greaterThan(L.literals.number(90), L.literals.number(80))
 * ),
 * then: () => L.transforms.string("Premium user"),
 * },
 * {
 * when: C.equals(status, L.literals.string("active")),
 * then: () => L.transforms.string("Active user"),
 * }
 * ],
 * defaultValue: () => L.transforms.string("Inactive user")
 * }));
 * ```
 */
 conditional<T extends ConditionalOutputType>(
 f: (C: ConditionBuilder) => ConditionalConfig<T>,
 metadata?: TransformMetadata,
 ): TransformOutput<T>;
 applyAction<const ActionRid extends KeyOf<Actions>>(
 actionRid: ActionRid,
 parameters: ActionParameters<Actions, ActionRid>,
 metadata?: TransformMetadata,
 ): TransformOutput<DataType.OntologyEdits>;
 callFunction<const FunctionRid extends KeyOf<Functions>, const Version extends KeyOf<Functions[FunctionRid]>>(
 functionRid: FunctionRid,
 functionVersion: Version,
 parameters: FunctionParameters<Functions, FunctionRid, Version>,
 metadata?: TransformMetadata,
 ): TransformOutput<Functions[FunctionRid][Version]["returnType"]>;
 inlineCode<T extends PrimitiveDataType>(
 parameters: {
 tsCode: string;
 variables: Array<{ name: string; value: Literal<PrimitiveDataType> | Reference<PrimitiveDataType> }>;
 },
 metadata?: TransformMetadata,
 ): TransformOutput<T>;
 /**
 * Never create new instances of `unsupportedTransform`. Only use it when you see an existing `unsupportedTransform` instance in a current Logic function and need to preserve the unsupported transform as-is.
 */
 unsupportedTransform(id: string): TransformOutput<any>;
 arrayToList<T extends PrimitiveDataType>(
 array: Reference<DataType.Array<T>> | Literal<DataType.Array<T>>,
 metadata?: TransformMetadata,
 ): TransformOutput<DataType.List<T>>;
 listToArray<T extends PrimitiveDataType>(
 list: Reference<DataType.List<T>>,
 metadata?: TransformMetadata,
 ): TransformOutput<DataType.Array<T>>;
 /**
 * Loop over elements, applying a transform or series of transforms to each.
 * For primitive arrays: first convert with arrayToLiteralList(), then pass to loop()
 * For object lists: pass directly to loop()
 */
 loop<T extends ListElementType, R extends LoopOutputType>(
 elements: Reference<DataType.List<T>>,
 lambdaFn: (element: Parameter<T>, index: Parameter<DataType.Integer>) => TransformOutput<R>,
 metadata?: LoopMetadata,
 ): TransformOutput<LoopReturnType<R>>;
 sortObjectSet<const ObjectTypeRid extends KeyOf<Objects>>(
 args: {
 objectSet: Reference<DataType.ObjectSet<ObjectTypeRid>>;
 sorting: Array<[KeyOf<ObjectTypes[ObjectTypeRid]["properties"]>, "ascending" | "descending"]>;
 },
 metadata?: TransformMetadata,
 ): TransformOutput<DataType.ObjectSet<ObjectTypeRid>>;
 /**
 * Traverse a link from a single object to either a single object or an object set depending on the link cardinality.
 */
 objectSearchAround<
 ObjectTypeRid extends KeyOf<Objects>,
 LinkApiName extends KeyOf<Objects[ObjectTypeRid]["links"]>,
 >(
 object: Reference<DataType.Object<ObjectTypeRid>>,
 linkApiName: LinkApiName,
 metadata?: TransformMetadata,
 ): TransformOutput<ObjectSearchAroundOutput<Objects[ObjectTypeRid]["links"][LinkApiName]["otherSide"]>>;
 /**
 * Traverse a link from an object set to find all related objects.
 */
 objectSetSearchAround<
 ObjectTypeRid extends KeyOf<Objects>,
 LinkApiName extends KeyOf<Objects[ObjectTypeRid]["links"]>,
 >(
 objectSet: Reference<DataType.ObjectSet<ObjectTypeRid>>,
 linkApiName: LinkApiName,
 metadata?: TransformMetadata,
 ): TransformOutput<DataType.ObjectSet<Objects[ObjectTypeRid]["links"][LinkApiName]["otherSide"]["objectTypeRid"]>>;
 /** Converts an ObjectSet to a CSV string representation suitable for LLM consumption. */
 objectSetToCSV<const ObjectTypeRid extends KeyOf<Objects>>(
 args: {
 objectSet: Reference<DataType.ObjectSet<ObjectTypeRid>>;
 /** Properties to include. If undefined or empty, all properties are selected. */
 properties?: Array<KeyOf<ObjectTypes[ObjectTypeRid]["properties"]>>;
 /** Whether to include the object set RID. Defaults to true. */
 includeObjectSetRid?: boolean;
 /** Maximum number of objects to print. Defaults to 10. */
 maxObjects?: number;
 },
