 unsupported(metadata: { id: string }): Expression<any, any>;
 unsupportedWindow(metadata: { id: string }): WindowInstance<any>;
}

/** When modifying an existing transform you must use its existing ID. Do not provide an ID for a new transform. */
type ExistingTransformId = string;

export type PathTransformMetadata = {
 id?: ExistingTransformId;
};

export type TransformMetadata = {
 name: string;
 position: Position;
 id?: ExistingTransformId;
};

export type UseLlmOutputMode = "simple" | "with_errors";
export type PromptPart = Column<DataType.Primitive> | Literal<DataType.String>;

export type UseLlmWithErrorsColumnType<OutputType extends DataType.Primitive> = DataType.Struct<{
 ok: OutputType;
 error: DataType.String;
}>;

export interface Transforms {
 useLlm<
 InputResource extends DataType.Tabular,
 NewColumnName extends string,
 OutputType extends DataType.Primitive,
 Mode extends UseLlmOutputMode,
 >(
 args: {
 prompt: (columnProvider: ColumnProvider<InputResource["schema"]>) => PromptPart[];
 input: TransformOutput<InputResource>;
 outputColumn: NewColumnName;
 systemPrompt: (columnProvider: ColumnProvider<InputResource["schema"]>) => PromptPart[];
 /** When using outputMode "with_errors" - wraps the output type in a struct with error info */
 outputMode: Mode;
 outputType: OutputType;
 },
 metadata: TransformMetadata,
 ): TransformOutput<
 DataType.Dataset<
 WithColumn<
 InputResource["schema"],
 NewColumnName,
 Mode extends "with_errors" ? UseLlmWithErrorsColumnType<OutputType> : OutputType
 >
 >
 >;

 unsupported(metadata: { position: Position; id: string }): UnsupportedTransformOutput;
}

export type UnsupportedTransformOutput = { output(parameterId: string): TransformOutput<any> };

export type OutputLocator =
 | {
 /** File name of output, should be provided when creating a new output. A name will be autogenerated if undefined.
 * The new output will be saved in the same directory as the pipeline builder, hence the name must be different than the name of the pipeline builder. */
 name: string | undefined;
 type: "name";
 }
 | {
 /** When modifying an existing output that has a rid you must use its existing Rid. Do not provide a Rid for a new output. */
 rid: string;
 type: "rid";
 };

export type OutputMetadata = {
 /** When modifying an existing output you must use its existing ID. Do not provide an ID for a new output. */
 id?: string;
};

export type PropertyMapping<ColumnName extends string = string> =
 | { type: "manual"; propertyName: string; sourceColumn: ColumnName }
 /** Will derive the property name from the column name using start case (e.g., pier_interchange -> Pier Interchange) */
 | { type: "auto"; sourceColumn: ColumnName };

export type GeotemporalSeriesReferenceConfig =
 /** Reference a geotemporal series output in the same pipeline. */
 | { type: "output"; output: Output<"geotemporalSeries"> }
 | {
 type: "geotemporalSeriesIntegrationRid";
 /** Reference a geotemporal series by RID. Use when the referenced integration is not an output of the pipeline. */
 rid: string;
 };

export type ObjectProperty<Schema extends TabularSchema, ColumnName extends KeyOf<Schema> = KeyOf<Schema>> = {
 type: Schema[ColumnName];
 mapping: PropertyMapping<ColumnName>;
 /** If present, this property will be a geotemporal series reference (GTSR) property. Type must be string. */
 geotemporalSeriesReferenceConfig?: GeotemporalSeriesReferenceConfig;
};

export type ObservationProperty<Schema extends TabularSchema, ColumnName extends KeyOf<Schema> = KeyOf<Schema>> = {
 type: Schema[ColumnName];
 mapping: PropertyMapping<ColumnName>;
 isStatic: boolean;
};

export type OutputKind = "dataset" | "mediaSet" | "objectType" | "geotemporalSeries";

export interface Output<T extends OutputKind = OutputKind> {
 type: "output";
 outputKind: T;
}

export interface Outputs {
 dataset<DatasetSchema extends TabularSchema, K extends keyof DatasetSchema>(args: {
 transformOutput: TransformOutput<DataType.Dataset<DatasetSchema>>;
 locator: OutputLocator;
 schema: Pick<DatasetSchema, K>;
 metadata: {
 position: Position;
 } & OutputMetadata;
 }): Output<"dataset">;
 mediaSet(args: {
 transformOutput: TransformOutput<DataType.MediaSet>;
 locator: OutputLocator;
 mediaType: AllowedMediaType;
 metadata: {
 position: Position;
 } & OutputMetadata;
 }): Output<"mediaSet">;
 objectType<DatasetSchema extends TabularSchema>(args: {
 transformOutput: TransformOutput<DataType.Dataset<DatasetSchema>>;
 objectTypeName: string;
 objectTypePluralName: string;
 /** When modifying an existing object type you must use its existing objectTypeId. Do not provide an objectTypeId for a new object type. */
 objectTypeId?: string;
 properties: Array<ObjectProperty<DatasetSchema>>;
 options: {
 allowEdits: boolean;
 primaryKeyPropertyName: string;
 titlePropertyName: string;
 };
 metadata: {
 position: Position;
 } & OutputMetadata;
 }): Output<"objectType">;
 geotemporalSeries<Schema extends TabularSchema, ColumnName extends KeyOf<Schema> = KeyOf<Schema>>(args: {
 transformOutput: TransformOutput<DataType.Dataset<Schema>>;
 locator: OutputLocator;
 position: PropertyMapping<ColumnName>;
 timestamp: PropertyMapping<ColumnName>;
 seriesId: PropertyMapping<ColumnName>;
 properties: Array<ObservationProperty<Schema>>;
 metadata: {
 position: Position;
 } & OutputMetadata;
 }): Output<"geotemporalSeries">;
 unsupported(metadata: { id: string }): Output<any>;
}

export interface PBBuilder {
 types: {
 array: <T extends DataType.Primitive>(elementType: T) => DataType.Array<T>;
 binary: DataType.Binary;
 boolean: DataType.Boolean;
 byte: DataType.Byte;
 date: DataType.Date;
 decimal: DataType.Decimal;
 double: DataType.Double;
 float: DataType.Float;
 integer: DataType.Integer;
 long: DataType.Long;
