 array: <T extends DataType.Primitive>(elements: Array<Literal<T>>) => Literal<DataType.Array<T>>;
 boolean: (value: boolean) => Literal<DataType.Boolean>;
 date: (value: string) => Literal<DataType.Date>;
 double: (value: number) => Literal<DataType.Double>;
 float: (value: string) => Literal<DataType.Float>;
 integer: (value: number) => Literal<DataType.Integer>;
 long: (value: number) => Literal<DataType.Long>;
