 joins: Joins;
 transformPath: <InputTabular extends DataType.Tabular, OutputTabular extends DataType.Tabular>(
 input: TransformOutput<InputTabular>,
 transformBuilder: (transforms: TransformBuilder<InputTabular>) => TransformBuilder<OutputTabular>,
 metadata: {
 name: string;
 comment?: string;
 position: Position;
 id?: ExistingTransformId;
 },
 ) => TransformOutput<OutputTabular>;
 outputs: Outputs;
 textNode(
 content: string,
 metadata: {
 position: Position;
 width?: number;
 height?: number;
 /** Preserve existing text node ID when modifying. Do not provide for new text nodes. */
 id?: string;
 },
 ): void;
}

export interface ObjectTargetSettings {
 ontologyRid: string;
 projectRid?: string;
}

export interface JobGrouping {
 // Don't include the id for new groupings, preserve it for existing ones
 id?: string;
 name?: string;
 description?: string;
 outputs: Output[];
