}
export interface SolutionDesignBuilder {
 /**
 * Create a Foundry component node. This represents a Foundry resource like an Object Type, Interface Type, Dataset, Model, etc.
 * Can also be a more abstract component representing a logical entity or idea.
 */
 foundryComponent(config: {
 componentType: ComponentType;
 name: string;
 description?: string;
 rid?: Rid;
 tags?: string[];
 icon?: IconName;
 color?: RgbaColor;
 attributeGroups?: AttributeGroup[]; // Attribute groups take up space. Each attribute group adds 20px of vertical height plus 20px per item
 x: number;
 y: number;
 width: number;
 height: number;
 id?: Id;
 parent?: Node;
 }): ConnectableNode;

