 name: string;
 color?: RgbaColor; // Optional: Default will be used if not specified
 tags?: string[];
 x: number;
 y: number;
 width: number;
 height: number;
 id?: Id;
 parent?: Node;
 }): Node;

 /**
 * Used to add annotations to the diagram, these can be large explanatory text blocks.
 * Supports basic HTML formatting.
 */
 comment(config: {
 description: string;
 tags?: string[];
 x: number;
 y: number;
 width: number;
 height: number;
 id?: Id;
 parent?: Node;
 }): Node;

 /**
 * Connect two nodes with an edge. Edge's can have labels that describe the relationship.
 * Labels should use line breaks if they are long. (more than a couple of words)
 * Only foundry component nodes can be connected - groups and comments cannot have edges.
 */
 connect(config: { source: ConnectableNode; target: ConnectableNode; label?: string; id?: Id }): Edge;
}

