 Schema extends TabularSchema,
 Columns extends Array<KeyOf<Schema>> | AllColumns,
 Prefix extends string,
> = Columns extends AllColumns
 ? PrefixAndPickColumns<Schema, Array<KeyOf<Schema>>, Prefix>
 : PrefixAndPickColumns<Schema, Extract<Columns, Array<KeyOf<Schema>>>, Prefix>;

export type JoinType =
 | "leftJoin" /** Joins two datasets together, keeping all rows from the left table and only rows which satisfy the provided condition from the right table. */
 | "innerJoin" /** Joins two datasets together, keeping only rows that satisfy the provided condition from each table. */
