Modify a solution design diagram using Solution Design DSL code.
 - The code should be a complete function in the format S => { ... }. Example:
 builder => {
 // Create groups for organizing nodes by layer
 const data_layer = builder.group({
 name: "Data Layer",
 color: "#E3F2FD",
 x: 50,
 y: 50,
 width: 1000,
 height: 400,
 });

 const ontology_layer = builder.group({
 name: "Ontology Layer",
 color: "#F3E5F5",
 x: 1100,
 y: 50,
 width: 600,
 height: 400,
 });

 // Create nodes for a simple data pipeline workflow
 const data_source = builder.foundryComponent({
 componentType: "magritte",
 name: "Customer Database Sync",
 description: "Syncs customer data from external CRM",
 x: 100,
 y: 100,
 width: 320,
 height: 128,
 parent: data_layer,
 });

 const dataset = builder.foundryComponent({
 componentType: "dataset",
 name: "Customer Dataset",
 description: "Cleaned and processed customer data",
 x: 500,
 y: 100,
 width: 320,
 height: 128,
 parent: data_layer,
 });

 // If editing a pre-existing node from the backend, include its id to preserve it.
 // Otherwise, omit the id field and one will be auto-generated.
 const customer_object = builder.foundryComponent({
 componentType: "object",
 name: "Customer",
 description: "Customer object type with properties",
 id: "ri.solution-design..node.customer-obj-123",
 x: 1150,
 y: 100,
 width: 320,
 height: 200,
 parent: ontology_layer,
 attributeGroups: [
 {
 type: "objectTypeProperty",
 title: "Properties",
 items: [
 { title: "Customer ID", propertyType: "STRING", isArray: false },
 { title: "Name", propertyType: "STRING", isArray: false },
 { title: "Email", propertyType: "STRING", isArray: false },
 { title: "Created Date", propertyType: "TIMESTAMP", isArray: false },
 ],
 },
 ],
 });

 // Add comment annotation
 const pipeline_comment = builder.comment({
 description: "<h3>Customer Data Pipeline</h3><p>This pipeline demonstrates:<ul><li>Data ingestion from CRM</li><li>Dataset transformation</li><li>Ontology object creation</li></ul></p>",
 x: 100,
 y: 500,
 width: 500,
 height: 150,
 });

 // Connect nodes with descriptive labels
 // If editing a pre-existing edge from the backend, include its id to preserve it.
 // Otherwise, omit the id field and one will be auto-generated.
 builder.connect({
 source: data_source,
 target: dataset,
 label: "ingests data into",
 id: "ri.solution-design.main.edge.standard.example-edge-123",
 });

 builder.connect({
 source: dataset,
 target: customer_object,
 label: "backs object type
via sync",
 });
}
