export interface Types<Objects extends ObjectTypes> {
 array: <T extends PrimitiveDataType>(elementType: T) => DataType.Array<T>;
 boolean: DataType.Boolean;
 date: DataType.Date;
 double: DataType.Double;
 float: DataType.Float;
 integer: DataType.Integer;
 list: <T extends PhysicalType>(elementType: T) => DataType.List<T>;
 long: DataType.Long;
 object: <const ObjectTypeRid extends KeyOf<Objects>>(
 objectTypeRid: ObjectTypeRid,
 ) => DataType.Object<ObjectTypeRid>;
 objectSet: <const ObjectTypeRid extends KeyOf<Objects>>(
 objectTypeRid: ObjectTypeRid,
 ) => DataType.ObjectSet<ObjectTypeRid>;
 short: DataType.Short;
 string: DataType.String;
 struct: <Shape extends { [name: string]: PrimitiveDataType }>(shape: Shape) => DataType.Struct<Shape>;
 timestamp: DataType.Timestamp;
}

/**
* Path to a field within a DataType.Struct. E.g., ["author", "email"]
*/
export type StructLocator<Shape extends { [name: string]: PrimitiveDataType }> = {
 [K in KeyOf<Shape>]: Shape[K] extends DataType.Struct<infer NestedShape>
 ? [K] | [K, ...StructLocator<NestedShape>]
 : [K];
}[KeyOf<Shape>];

export type StructFieldAtPath<
 Shape extends { [name: string]: PrimitiveDataType },
 Path extends StructLocator<Shape>,
> = Path extends readonly [infer First extends keyof Shape, ...infer Rest]
 ? Rest extends readonly []
 ? Shape[First]
 : Shape[First] extends DataType.Struct<infer NestedShape>
 ? Rest extends StructLocator<NestedShape>
 ? StructFieldAtPath<NestedShape, Rest>
 : never
 : never
 : never;

export type ExpressionMetadata = {
 /** When modifying an existing expression you must use its existing ID. Do not provide an ID for a new expression. */
 id?: string;
};

export interface Expressions {
 /**
 * Extracts a field from a struct.
 *
 * @param struct
 * @param locator - Extract inner elements with multiple entries like ["author", "email"].
 */
 getStructField<Shape extends { [name: string]: PrimitiveDataType }, const Path extends StructLocator<Shape>>(
 args: {
 locator: Path;
 struct: ExpressionInput<DataType.Struct<Shape>>;
 },
 metadata?: ExpressionMetadata,
 ): Expression<StructFieldAtPath<Shape, Path>>;
 /**
 * Creates a struct from individual field values.
 *
 * @param fields - Object mapping field names to their values (inputs, transforms, literals, or expressions).
 */
 createStruct<Shape extends { [name: string]: ExpressionInput<PrimitiveDataType> }>(
 fields: Shape,
 metadata?: ExpressionMetadata,
 ): Expression<
 DataType.Struct<{
 [name in keyof Shape]: Shape[name] extends ExpressionInput<infer T> ? T : never;
 }>
 >;
 /**
 * Never create new instances of `unsupportedExpression`. Only use it when you see an existing `unsupportedExpression` instance in a current Logic function and need to preserve the unsupported expression as-is.
 */
 unsupportedExpression(id: string): Expression<any>;
}

export type InputType =
 | PrimitiveDataType
 | DataType.Object<KeyOf<ObjectTypes>>
 | DataType.ObjectSet<KeyOf<ObjectTypes>>
 | DataType.List<DataType.Object<KeyOf<ObjectTypes>>>;

/**
* Must be a valid identifier: starts with a letter or underscore, followed by letters, digits, or underscores.
* Max 100 characters. Cannot be a reserved keyword (link, object, ontology, ontologyobject, primarykey, property, relation, rid, typeid).
*/
export type ApiName = string;

export type InputArgs<T extends InputType> = {
 /** Must be unique across the function's inputs. */
 apiName: ApiName;
 type: T;
 /** When modifying an existing transform you must use its existing ID. Do not provide an ID for a new transform. */
 id?: string;
};
export interface InputFunction {
 <T extends InputType>(args: InputArgs<T>): Parameter<T>;
 /**
 * Never create new instances of `input.unsupported`. Only use it when you see an existing `input.unsupported` instance in a current Logic function and need to preserve the unsupported input as-is.
 */
 unsupported(apiName: string): Parameter<any>;
}

export interface DebugOutput {
 type: "debugOutput";
}

export type DebugOutputArgs = {
 /** Must be unique across the function's debug outputs. */
 apiName: ApiName;
 /** Human-readable label shown in the evaluation suite to identify this debug output. If omitted, defaults to "{blockName} (block)". */
 displayName?: string;
 /** When modifying an existing debug output you must use its existing ID. Do not provide an ID for a new debug output. */
