 /** Custom display name for the index argument (default: "Index") */
 indexName?: string;
};

/** Function version in the semver format, e.g., "3.0.0", "0.0.1-rc.1" */
// wipe-disable
export type FunctionVersionString = string;

type ActionParameter<T extends PhysicalType> = T extends PrimitiveDataType ? Literal<T> | Reference<T> : Reference<T>;

export type ActionParameters<Actions extends ActionTypes, ActionRid extends KeyOf<Actions>> = {
 [K in keyof Actions[ActionRid]["parameters"]]: ActionParameter<Actions[ActionRid]["parameters"][K]["dataType"]>;
};

type FunctionParameter<T extends PhysicalType> = T extends PrimitiveDataType ? Literal<T> | Reference<T> : Reference<T>;

export type FunctionParameters<
 Functions extends FunctionTypes,
 FunctionRid extends KeyOf<Functions>,
 Version extends KeyOf<Functions[FunctionRid]>,
> = {
 [K in keyof Functions[FunctionRid][Version]["parameters"]]: FunctionParameter<
 Functions[FunctionRid][Version]["parameters"][K]["dataType"]
 >;
};

