/**
* Resolves the column type for a given schema and column name.
* When the schema type can't be inferred and falls back to TabularSchema's index signature giving Primitive
* return `any` instead so expressions like equals() accept the column without type errors.
*/
type ColumnType<Schema extends TabularSchema, ColumnName extends KeyOf<Schema>> = [DataType.Primitive] extends [
 Schema[ColumnName],
]
 ? [Schema[ColumnName]] extends [DataType.Primitive]
 ? any
 : Schema[ColumnName]
 : Schema[ColumnName];

