export type PickColumns<Schema extends TabularSchema, Columns extends Array<KeyOf<Schema>>> = {
 [ColumnName in Columns[number]]: Schema[ColumnName];
};

export type PrefixAndPickColumns<
 Schema extends TabularSchema,
 Columns extends Array<KeyOf<Schema>>,
 Prefix extends string,
> = {
 [ColumnName in Columns[number] as `${Prefix}${ColumnName}`]: Schema[ColumnName];
};

export type AllColumns = "AllColumns" & { readonly __brand: unique symbol };

/** Resolves columns for a join side without prefix */
export type ResolveJoinColumns<
 Schema extends TabularSchema,
 Columns extends Array<KeyOf<Schema>> | AllColumns,
> = Columns extends AllColumns ? Schema : PickColumns<Schema, Extract<Columns, Array<KeyOf<Schema>>>>;

/** Resolves columns for a join side with prefix applied */
export type PrefixResolveJoinColumns<
 Schema extends TabularSchema,
 Columns extends Array<KeyOf<Schema>> | AllColumns,
 Prefix extends string,
> = Columns extends AllColumns
 ? PrefixAndPickColumns<Schema, Array<KeyOf<Schema>>, Prefix>
 : PrefixAndPickColumns<Schema, Extract<Columns, Array<KeyOf<Schema>>>, Prefix>;

export type JoinType =
 | "leftJoin" /** Joins two datasets together, keeping all rows from the left table and only rows which satisfy the provided condition from the right table. */
 | "innerJoin" /** Joins two datasets together, keeping only rows that satisfy the provided condition from each table. */
 | "outerJoin"; /** Outer joins the provided dataset inputs together, keeping all rows from both datasets. Columns have nulls when there is no row satisfying the provided condition. */
export type FilterJoinType =
 | "semiJoin" /** Semi joins left and right dataset inputs together. This removes all rows that don't match the join condition. */
 | "antiJoin" /** Anti joins left and right dataset inputs, removing all rows from the left relation that match the provided condition. */;

export interface Joins {
 /** Returns a marker to select all columns from a side of a join */
 allColumns(): AllColumns;

 join<
 LeftTabular extends DataType.Tabular,
 RightTabular extends DataType.Tabular,
 LeftColumns extends Array<KeyOf<LeftTabular["schema"]>> | AllColumns,
 RightColumns extends Array<KeyOf<RightTabular["schema"]>> | AllColumns,
 RightPrefix extends string,
 >(
 args: {
 joinType: JoinType;
 left: TransformOutput<LeftTabular>;
 right: TransformOutput<RightTabular>;
 on: (params: {
 leftColumns: ColumnProvider<LeftTabular["schema"]>;
 rightColumns: ColumnProvider<RightTabular["schema"]>;
 }) => Expression<DataType.Boolean, ExpressionKind.ColumnKind>;
 leftColumns: LeftColumns;
 rightColumns: RightColumns;
 rightPrefix?: RightPrefix;
 },
 metadata: TransformMetadata,
 ): TransformOutput<
 DataType.Dataset<
 ResolveJoinColumns<LeftTabular["schema"], LeftColumns> &
 PrefixResolveJoinColumns<RightTabular["schema"], RightColumns, RightPrefix>
 >
 >;

 filterJoin<
 LeftTabular extends DataType.Tabular,
 RightTabular extends DataType.Tabular,
 LeftColumns extends Array<KeyOf<LeftTabular["schema"]>> | AllColumns,
 >(
 args: {
 type: FilterJoinType;
