 position: Position;
 dimensions: Dimensions;
}

// Only foundry component nodes can be connected with edges
export type ConnectableNode = Node & { nodeType: "foundryComponent" };

// Attribute Groups. These are typically used for displaying properties on a node
export type AttributeGroup = ObjectTypePropertyGroup | InterfaceTypePropertyGroup | GenericAttributeGroup;

export interface ObjectTypeOrInterfaceTypeProperty {
 id?: Id;
