// Nodes
export namespace NodeType {
 export interface FoundryComponent {
 type: ComponentType;
 name: string;
 description?: string;
 rid?: Rid; // Optional: linked Foundry resource
 tags?: string[];
 icon?: IconName;
 color?: RgbaColor;
 attributeGroups?: AttributeGroup[];
 }

 export interface Group {
 name: string;
 color?: RgbaColor;
 tags?: string[];
 }

 export interface Comment {
 description: string; // HTML content
 tags?: string[];
 }
}
export interface Node {
 type: "node";
 id: Id;
 nodeType: "foundryComponent" | "customGroup" | "comment";
 data: NodeType.FoundryComponent | NodeType.Group | NodeType.Comment;
 parentNode?: Node;
 position: Position;
 dimensions: Dimensions;
}

// Only foundry component nodes can be connected with edges
export type ConnectableNode = Node & { nodeType: "foundryComponent" };

// Attribute Groups. These are typically used for displaying properties on a node
export type AttributeGroup = ObjectTypePropertyGroup | InterfaceTypePropertyGroup | GenericAttributeGroup;

export interface ObjectTypeOrInterfaceTypeProperty {
 id?: Id;
 title: string;
 propertyType: ObjectOrInterfacePropertyType;
 isArray: boolean;
}

export interface ObjectTypePropertyGroup {
 id?: Id;
 type: "objectTypeProperty";
 title: string;
 items: ObjectTypeOrInterfaceTypeProperty[];
}

export interface InterfaceTypePropertyGroup {
 id?: Id;
 type: "interfaceTypeProperty";
 title: string;
 items: ObjectTypeOrInterfaceTypeProperty[];
}

export interface GenericAttributeItem {
 id?: Id;
 title: string;
 icon: IconName;
}

export interface GenericAttributeGroup {
 id?: Id;
 type: "generic";
 title: string;
 items: GenericAttributeItem[];
}

// Edges
export interface Edge {
 type: "edge";
 id: Id;
 source: ConnectableNode;
 target: ConnectableNode;
 label?: string;
}

// Full diagram
export interface Diagram {
 type: "diagram";
 name: string;
 description?: string;
 nodes: Node[];
 edges: Edge[];
}
export interface SolutionDesignBuilder {
 /**
 * Create a Foundry component node. This represents a Foundry resource like an Object Type, Interface Type, Dataset, Model, etc.
 * Can also be a more abstract component representing a logical entity or idea.
 */
 foundryComponent(config: {
 componentType: ComponentType;
 name: string;
 description?: string;
 rid?: Rid;
 tags?: string[];
 icon?: IconName;
 color?: RgbaColor;
 attributeGroups?: AttributeGroup[]; // Attribute groups take up space. Each attribute group adds 20px of vertical height plus 20px per item
 x: number;
 y: number;
 width: number;
 height: number;
 id?: Id;
 parent?: Node;
 }): ConnectableNode;

 /**
 * Create a group node. This is a container for other nodes to help with organization. Common groups are data layer, ontology
 * layer, application layer, etc.
 */
 group(config: {
 name: string;
 color?: RgbaColor; // Optional: Default will be used if not specified
 tags?: string[];
 x: number;
 y: number;
 width: number;
 height: number;
 id?: Id;
 parent?: Node;
 }): Node;

 /**
 * Used to add annotations to the diagram, these can be large explanatory text blocks.
 * Supports basic HTML formatting.
 */
 comment(config: {
 description: string;
 tags?: string[];
 x: number;
 y: number;
 width: number;
 height: number;
 id?: Id;
 parent?: Node;
 }): Node;

 /**
 * Connect two nodes with an edge. Edge's can have labels that describe the relationship.
 * Labels should use line breaks if they are long. (more than a couple of words)
 * Only foundry component nodes can be connected - groups and comments cannot have edges.
 */
 connect(config: { source: ConnectableNode; target: ConnectableNode; label?: string; id?: Id }): Edge;
}

/**
* Configuration for creating a new diagram
*/
export interface DiagramConfig {
 name: string;
 description?: string;
}

 - Builder implementation for reference:
 const MIN_NODE_WIDTH = 100;
const MIN_NODE_HEIGHT = 100;
const MIN_COMMENT_WIDTH = 120;
const MIN_COMMENT_HEIGHT = 64;
const DEFAULT_NODE_WIDTH = 320;
const DEFAULT_NODE_HEIGHT = 128;
const DEFAULT_GROUP_COLOR = "rgba(237,231,225, 0.3)";
function generateUUID() {
 if (typeof crypto !== "undefined" && crypto.randomUUID) {
 return crypto.randomUUID();
 }
 return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, c => {
 const r = (Math.random() * 16) | 0;
 const v = c === "x" ? r : (r & 0x3) | 0x8;
 return v.toString(16);
 });
}
class SolutionDesignBuilderImpl {
 config;
 nodes = [];
 edges = [];
 constructor(config) {
 this.config = config;
 }
 foundryComponent(config) {
 const width = Math.max(config.width, MIN_NODE_WIDTH);
 const height = Math.max(config.height, MIN_NODE_HEIGHT);
 const nodeId = config.id || generateUUID();
 const data = {
 type: config.componentType,
 name: config.name,
 description: config.description,
 rid: config.rid,
 tags: config.tags ?? [],
 icon: config.icon ?? "annotation",
 color: config.color,
 attributeGroups: config.attributeGroups ?? [],
 };
 const node = {
 type: "node",
 id: nodeId,
 nodeType: "foundryComponent",
 data,
 position: { x: config.x, y: config.y },
 dimensions: { width, height },
 parentNode: config.parent,
 };
 this.nodes.push(node);
 return node;
 }
 group(config) {
 const nodeId = config.id || generateUUID();
 const data = {
 name: config.name,
 color: config.color ?? DEFAULT_GROUP_COLOR,
 tags: config.tags ?? [],
 };
 const node = {
 type: "node",
 id: nodeId,
 nodeType: "customGroup",
 data,
 position: { x: config.x, y: config.y },
 dimensions: { width: config.width, height: config.height },
 parentNode: config.parent,
 };
 this.nodes.push(node);
 return node;
 }
 comment(config) {
 const width = Math.max(config.width, MIN_COMMENT_WIDTH);
 const height = Math.max(config.height, MIN_COMMENT_HEIGHT);
 const nodeId = config.id || generateUUID();
 const data = {
 description: config.description,
 tags: config.tags ?? [],
 };
 const node = {
 type: "node",
 id: nodeId,
 nodeType: "comment",
 data,
 position: { x: config.x, y: config.y },
 dimensions: { width, height },
 parentNode: config.parent,
 };
 this.nodes.push(node);
 return node;
 }
 connect(config) {
 const edgeId = config.id || generateUUID();
 const edge = {
 type: "edge",
 id: edgeId,
 source: config.source,
 target: config.target,
 label: config.label,
 };
 this.edges.push(edge);
 return edge;
 }
 build() {
 return {
 type: "diagram",
 name: this.config.name,
 description: this.config.description,
 nodes: this.nodes,
 edges: this.edges,
 };
 }
}
function defineDiagram(config, definition) {
 const builder = new SolutionDesignBuilderImpl(config);
 definition(builder);
 return builder.build();
}
